import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';
import { FaSearch, FaEllipsisV, FaFileExcel, FaPlus } from 'react-icons/fa';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 25;

const Inventory = ({ clientCode }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);
  const [selectedRows, setSelectedRows] = useState([]);

  useEffect(() => {
    if (!clientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: clientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [clientCode]);

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
  };

  // Selection state
  const allSelected = paginatedLabels.length > 0 && paginatedLabels.every(l => selectedRows.includes(l.Id));
  const toggleSelectAll = () => {
    if (allSelected) setSelectedRows(selectedRows.filter(id => !paginatedLabels.some(l => l.Id === id)));
    else setSelectedRows([...new Set([...selectedRows, ...paginatedLabels.map(l => l.Id)])]);
  };
  const toggleSelectRow = (id) => {
    setSelectedRows(selectedRows.includes(id) ? selectedRows.filter(i => i !== id) : [...selectedRows, id]);
  };

  return (
    <div style={{ minHeight: '100vh', background: '#f7f8fa' }}>
      <Header userInfo={{ ClientCode: clientCode }} />
      <div className="container py-4" style={{ maxWidth: 1300 }}>
        {/* Top bar */}
        <div className="d-flex flex-wrap align-items-center justify-content-between mb-3 gap-2" style={{ background: '#fff', borderRadius: 12, boxShadow: '0 2px 12px #0001', padding: '18px 24px' }}>
          <div className="d-flex align-items-center gap-2" style={{ flex: 1, minWidth: 320 }}>
            <div style={{ position: 'relative', width: 260 }}>
              <input
                ref={searchInputRef}
                type="text"
                className="form-control ps-5"
                style={{ borderRadius: 8, background: '#f7f8fa', border: '1.5px solid #e0e0e0', height: 40, fontSize: '1rem' }}
                placeholder="Search..."
                value={search}
                onChange={handleSearchChange}
              />
              <span style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', color: '#b0b0b0', fontSize: 18 }}>
                <FaSearch />
              </span>
            </div>
            <button className="btn btn-outline-secondary d-flex align-items-center" style={{ borderRadius: 8, fontWeight: 500, height: 40, fontSize: '1rem', border: '1.5px solid #e0e0e0', background: '#fff' }}>
              Filters <span className="ms-2" style={{ fontSize: 14 }}>▼</span>
            </button>
            {/* Show active filters as chips if needed */}
          </div>
          <div className="d-flex align-items-center gap-2">
            <button
              className="btn btn-outline-success d-flex align-items-center"
              style={{ borderRadius: 8, fontWeight: 500, height: 40, fontSize: '1rem', border: '1.5px solid #22bb33', background: '#fff' }}
              onClick={handleExport}
            >
              <FaFileExcel className="me-2" /> Export
            </button>
            <button className="btn btn-primary d-flex align-items-center" style={{ borderRadius: 8, fontWeight: 500, height: 40, fontSize: '1rem', background: '#2563eb', border: 'none' }}>
              <FaPlus className="me-2" /> New Product
            </button>
          </div>
        </div>
        {/* Table */}
        <div className="d-flex justify-content-center">
          <div className="table-responsive" style={{ maxWidth: '1200px', minHeight: '60vh', margin: '0 auto', borderRadius: 14, overflow: 'hidden', boxShadow: '0 4px 24px #0002', background: '#fff', border: '1.5px solid #e0e0e0' }}>
            <table className="table align-middle mb-0" style={{ width: '100%', background: '#fff', borderRadius: 14, overflow: 'hidden', borderCollapse: 'separate', borderSpacing: 0, fontSize: '1.04rem' }}>
              <thead style={{ position: 'sticky', top: 0, zIndex: 2, background: '#fff', borderTopLeftRadius: 14, borderTopRightRadius: 14, boxShadow: '0 2px 8px #0001' }}>
                <tr style={{ borderRadius: 14 }}>
                  <th style={{ width: 40, background: '#fff', border: 'none', padding: '0 10px' }}>
                    <input type="checkbox" checked={allSelected} onChange={toggleSelectAll} />
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopLeftRadius: 14, fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>Product Name</th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>Category</th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>SKU</th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>Gross Wt</th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>Net Wt</th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>Branch</th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopRightRadius: 14, fontSize: '1.08rem', padding: '16px 14px', border: 'none' }}>Status</th>
                  <th style={{ width: 40, background: '#fff', border: 'none' }}></th>
                </tr>
              </thead>
              <tbody>
                {paginatedLabels.map((label, idx) => (
                  <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer', borderBottom: '1.5px solid #e0e0e0' }}
                    onMouseOver={e => e.currentTarget.style.background = '#f0f0f0'}
                    onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                  >
                    <td style={{ width: 40, border: 'none', padding: '0 10px' }}>
                      <input type="checkbox" checked={selectedRows.includes(label.Id)} onChange={() => toggleSelectRow(label.Id)} />
                    </td>
                    <td style={{ fontWeight: 500, color: '#222', letterSpacing: 0.2, padding: '14px 12px', border: 'none' }}>{label.ProductName}</td>
                    <td style={{ padding: '14px 12px', border: 'none' }}>{label.CategoryName}</td>
                    <td style={{ padding: '14px 12px', border: 'none' }}>{label.ItemCode}</td>
                    <td style={{ padding: '14px 12px', border: 'none' }}>{label.GrossWt}</td>
                    <td style={{ padding: '14px 12px', border: 'none' }}>{label.NetWt}</td>
                    <td style={{ padding: '14px 12px', border: 'none' }}>{label.BranchName}</td>
                    <td style={{ padding: '14px 12px', border: 'none' }}>
                      <span className={`badge`} style={{ background: label.Status === 'Active' ? '#e6f9ed' : '#ffeaea', color: label.Status === 'Active' ? '#22bb33' : '#e74c3c', fontWeight: 600, fontSize: '1em', padding: '7px 18px', borderRadius: 16, border: 'none' }}>{label.Status}</span>
                    </td>
                    <td style={{ width: 40, border: 'none', textAlign: 'center' }}>
                      <button className="btn btn-link p-0" style={{ color: '#b0b0b0' }}><FaEllipsisV /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
        {/* Pagination */}
        {totalPages > 1 && !search && (
          <div className="d-flex justify-content-center align-items-center mt-4">
            <nav>
              <ul className="pagination mb-0" style={{ background: '#fff', borderRadius: 8, boxShadow: '0 1px 6px #0001', padding: '8px 18px' }}>
                <li className={`page-item${page === 1 ? ' disabled' : ''}`}><button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1.1rem' }} onClick={() => handlePageChange(page - 1)}>&laquo;</button></li>
                {[...Array(totalPages)].map((_, idx) => (
                  <li key={idx} className={`page-item${page === idx + 1 ? ' active' : ''}`}>
                    <button className="page-link" style={{ border: 'none', background: idx + 1 === page ? '#2563eb' : 'none', color: idx + 1 === page ? '#fff' : '#2563eb', fontWeight: 600, fontSize: '1.1rem', borderRadius: 6, margin: '0 2px' }} onClick={() => handlePageChange(idx + 1)}>{idx + 1}</button>
                  </li>
                ))}
                <li className={`page-item${page === totalPages ? ' disabled' : ''}`}><button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1.1rem' }} onClick={() => handlePageChange(page + 1)}>&raquo;</button></li>
              </ul>
            </nav>
          </div>
        )}
      </div>
    </div>
  );
};

export default Inventory;
